1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two live cells that each have only one neighbor (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep alive a live cell with three neighbors (survival)", () => {
15	    // (1,0) has three live neighbors: (0,0), (2,0), (1,1) -> survives
16	    expect(nextGeneration([[0, 0], [2, 0], [1, 1], [1, 0]])).toContainEqual([1, 0]);
17	  });
18	  it("should kill a live cell with four neighbors (overpopulation)", () => {
19	    // Center cell (1,1) has four live neighbors -> dies by overpopulation
20	    expect(
21	      nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]])
22	    ).not.toContainEqual([1, 1]);
23	  });
24	  it("should bring a dead cell with exactly three neighbors to life (reproduction)", () => {
25	    // Dead cell (1,1) has three live neighbors: (0,0), (1,0), (0,1) -> comes alive
26	    expect(nextGeneration([[0, 0], [1, 0], [0, 1]])).toContainEqual([1, 1]);
27	  });
28	  it("should oscillate a blinker, including negative coordinates", () => {
29	    // Gen 0: vertical triple (0,0),(0,1),(0,2)
30	    // Gen 1: horizontal triple (-1,1),(0,1),(1,1) — note negative x coordinate
31	    const sortByTuple = (cells: [number, number][]) =>
32	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
33	    expect(sortByTuple(nextGeneration([[0, 0], [0, 1], [0, 2]]))).toEqual(
34	      sortByTuple([[-1, 1], [0, 1], [1, 1]])
35	    );
36	  });
37	  it.todo("should leave a block still life unchanged");
38	});
